async def seed_piscinas():
    """Populate the database with Piscinas/Praias Fluviais data"""
    print("🏊 A popular base de dados com Praias Fluviais e Piscinas Naturais de Portugal...")

    # Delete existing piscinas items
    result = await db.heritage_items.delete_many({"category": "piscinas"})
    print(f"   Removidos {result.deleted_count} itens existentes da categoria piscinas")

    # Insert new items
    items_to_insert = []
    for praia in PISCINAS_DATA:
        item = {
            "id": str(uuid.uuid4()),
            "name": praia["name"],
            "description": praia["description"],
            "category": "piscinas",
            "subcategory": praia.get("subcategory"),
            "region": praia["region"],
            "location": praia.get("location"),
            "address": praia.get("address"),
            "image_url": praia.get("image_url"),
            "tags": praia.get("tags", []),
            "related_items": [],
            "metadata": praia.get("metadata", {}),
            "created_at": datetime.now(timezone.utc)
        }
        items_to_insert.append(item)

    if items_to_insert:
        await db.heritage_items.insert_many(items_to_insert)
        print(f"   ✅ Inseridos {len(items_to_insert)} itens de Praias Fluviais e Piscinas Naturais")

    # Count items by region
    print("\n📊 Distribuição por região:")
    regions = ["norte", "centro", "alentejo", "algarve", "lisboa", "madeira", "acores"]
    for region in regions:
        count = await db.heritage_items.count_documents({"category": "piscinas", "region": region})
        if count > 0:
            print(f"   - {region.capitalize()}: {count} praias")

    # Total count
    total = await db.heritage_items.count_documents({"category": "piscinas"})
    print(f"\n   📊 Total de Praias Fluviais na base de dados: {total}")

    print("\n✅ Base de dados populada com sucesso!")

if __name__ == "__main__":
    asyncio.run(seed_piscinas())
